import pybullet as p
import pybullet_data as pd
import time
p.connect(p.GUI)
p.setAdditionalSearchPath(pd.getDataPath())
offset = 0
for scale in range (1,15,2):
  ball = p.loadURDF("soccerball.urdf",[offset,0,1], globalScaling=scale*0.05)
  p.changeDynamics(ball,-1,linearDamping=0, angularDamping=0, rollingFriction=0.01, spinningFriction=0.01)
  p.changeVisualShape(ball,-1,rgbaColor=[0.8,0.8,0.8,1])
  offset += 2*scale*0.05
p.loadURDF("plane.urdf")
p.loadURDF("cube_small.urdf", [2, 0, 0.5])
p.setGravity(0,0,-10)
p.setRealTimeSimulation(1)

radius = 0.025
distance = 3
yaw = 135
pitch = -11
targetPos = [0, 0, 0]
p.resetDebugVisualizerCamera(distance, yaw, pitch, targetPos)



while p.isConnected():
  #p.getCameraImage(320,200, renderer=p.ER_BULLET_HARDWARE_OPENGL)
  time.sleep(0.5)
  
  # When p.setRealTimeSimulation(1) is active, 
  # you generally do not call p.stepSimulation() within your main simulation loop.
  # PyBullet handles the time stepping automatically.
  #
